import java.io.*;

public class XSSFixedCode {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));

        System.out.println("Enter your name: ");
        String userInput = br.readLine();

        // Sanitize user input by escaping special HTML characters
        String sanitizedInput = escapeHtml(userInput);

        // Output sanitized user input to the webpage
        System.out.println("<p>Welcome, " + sanitizedInput + "!</p>");
    }

    private static String escapeHtml(String input) {
        return input.replaceAll("&", "&amp;")
                    .replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("\"", "&quot;")
                    .replaceAll("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
